import React from 'react'
import { GameRunningStatus } from '../types'

/**
 * Time usage record.
 */
interface IRecordTime {
  /**
   * Cumulative use of time.
   */
  usedTime: number
  /**
   * Timestamp of the last time the timer started.
   */
  lastStartTime: number
}

/**
 * Return elapsed time (milliseconds) in game.
 */
export function useElapsedTime(status: GameRunningStatus): number {
  const [{ usedTime, lastStartTime }, setRecordTime] =
    React.useState<IRecordTime>({
      usedTime: 0,
      lastStartTime: -1,
    })

  switch (status) {
    case GameRunningStatus.PENDING: {
      if (usedTime !== 0 || lastStartTime !== -1) {
        setRecordTime({ usedTime: 0, lastStartTime: -1 })
      }
      return 0
    }
    case GameRunningStatus.RUNNING: {
      if (lastStartTime === -1) {
        setRecordTime({ usedTime, lastStartTime: Date.now() })
        return usedTime
      }
      return usedTime + Date.now() - lastStartTime
    }
    case GameRunningStatus.PAUSED: {
      if (lastStartTime !== -1) {
        const nextUsedTime = usedTime + Date.now() - lastStartTime
        setRecordTime({ usedTime: nextUsedTime, lastStartTime: -1 })
        return nextUsedTime
      }
      return usedTime
    }
    case GameRunningStatus.FINISHED: {
      if (lastStartTime !== -1) {
        const nextUsedTime = usedTime + Date.now() - lastStartTime
        setRecordTime({ usedTime: nextUsedTime, lastStartTime: -1 })
        return nextUsedTime
      }
      return usedTime
    }
    default:
      throw new TypeError(
        `[usedRecordTime] expect a GameRunningState, but got (${status})`,
      )
  }
}
