import { GameRunningStatus } from '@kyokuya/react-game-core'
import {
  KyokuyaSudokuActionType,
  KyokuyaSudokuContext,
} from '@kyokuya/react-sudoku'
import Button from '@material-ui/core/Button'
import GamePausedIcon from '@material-ui/icons/PauseCircleFilled'
import GamePendingIcon from '@material-ui/icons/PlayArrow'
import React, { useCallback, useContext } from 'react'

export const KyokuyaSudokuGameOverlay: React.FC = () => {
  const { gameStatus, dispatch } = useContext(KyokuyaSudokuContext)

  // Start game.
  const startGame = useCallback(
    () => dispatch({ type: KyokuyaSudokuActionType.START }),
    [dispatch],
  )

  // Resume game.
  const resumeGame = useCallback(
    () => dispatch({ type: KyokuyaSudokuActionType.RESUME }),
    [dispatch],
  )

  switch (gameStatus) {
    case GameRunningStatus.PENDING: {
      return (
        <div className="kyokuya-sudoku-game__overlay">
          <Button
            className="kyokuya-sudoku-game__start-button"
            variant="contained"
            color="primary"
            startIcon={<GamePendingIcon />}
            onClick={startGame}
          >
            Start
          </Button>
        </div>
      )
    }
    case GameRunningStatus.PAUSED: {
      return (
        <div className="kyokuya-sudoku-game__overlay">
          <Button
            variant="contained"
            color="primary"
            startIcon={<GamePausedIcon />}
            onClick={resumeGame}
          >
            Resume
          </Button>
        </div>
      )
    }
    case GameRunningStatus.FINISHED: {
      return (
        <div className="kyokuya-sudoku-game__overlay">
          <p className="kyokuya-sudoku-game__finished-banner">🎉 You win!</p>
        </div>
      )
    }
    default:
      return null
  }
}
