import type { SudokuBoard } from '@algorithm.ts/sudoku'
import {
  copySudokuBoard,
  createSegmentCodeMap,
  createSudokuBoard,
} from '@algorithm.ts/sudoku'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { createDuplicatedMap } from '../util/duplicated'
import { getSudokuCreator } from '../util/sudoku'

/**
 * Data type provided by PostLayoutContext.
 */
export interface IKyokuyaSudokuState {
  /**
   * Sudoku size, sqrt of the number of rows.
   */
  SUDOKU_SIZE_SQRT: 2 | 3 | 4
  /**
   * Game difficulty.
   */
  difficulty: number
  /**
   * Displayed radix.
   */
  radix: 10 | 16
  /**
   * Game status.
   */
  gameStatus: GameRunningStatus
  /**
   * Total score.
   */
  score: number
  /**
   * Sudoku puzzle.
   */
  puzzle: Readonly<SudokuBoard>
  /**
   * Solution of the puzzle.
   */
  solution: Readonly<SudokuBoard>
  /**
   * Attempt on the puzzle.
   */
  attempt: Readonly<SudokuBoard>
  /**
   * segmentCodeMap is a mapping table for quickly located the sub-matrix of a
   * grid.
   */
  segmentNoMap: ReadonlyArray<number>
  /**
   * Duplicated grids
   */
  duplicatedMap: ReadonlyArray<ReadonlyArray<boolean>>
  /**
   * Currently activated board cell.
   */
  activatedCell: Readonly<{ r: number; c: number }>
  /**
   * The coordinate of the board cell for hint.
   */
  hintCell: Readonly<{ r: number; c: number; v: number }>
  /**
   * Used to judge if the game has restarted.
   */
  gameTick: number
  /**
   * Times of attempt on the current game.
   */
  attemptTick: number
  /**
   * To retrigger the hint animation when the multiple times hint requests on a
   * same cell were fired.
   */
  hintTick: number
}

export const initKyokuyaSudokuState = (
  loadData?: () => Partial<IKyokuyaSudokuState>,
): IKyokuyaSudokuState => {
  const data: Partial<IKyokuyaSudokuState> =
    loadData instanceof Function ? loadData() : {}

  const {
    SUDOKU_SIZE_SQRT = 3,
    difficulty = 20,
    score = 0,
    radix = 10,
    activatedCell = { r: -1, c: -1 },
    gameTick = 0,
  } = data
  const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT

  let { puzzle, solution } = data
  if (puzzle == null || solution == null) {
    const creator = getSudokuCreator(SUDOKU_SIZE_SQRT)
    ;({ puzzle, solution } = creator.createSudoku(difficulty / 100))
  }

  const attempt = createSudokuBoard(SUDOKU_SIZE)
  copySudokuBoard(puzzle, attempt as SudokuBoard)

  return {
    SUDOKU_SIZE_SQRT,
    difficulty,
    radix,
    gameStatus: GameRunningStatus.PENDING,
    score,
    attempt,
    puzzle,
    solution,
    segmentNoMap: createSegmentCodeMap(SUDOKU_SIZE_SQRT),
    duplicatedMap: createDuplicatedMap(SUDOKU_SIZE),
    activatedCell: { r: activatedCell.r, c: activatedCell.c },
    hintCell: { r: -1, c: -1, v: -1 },
    gameTick,
    attemptTick: 0,
    hintTick: 0,
  }
}
