import type { IStorage } from '@kyokuya/react-storage'
import type { IKyokuyaSudokuState } from '@kyokuya/react-sudoku'
import { useEffect } from 'react'

export const useKyokuyaSudokuStatePersistEffect = (
  storage: IStorage<Partial<IKyokuyaSudokuState>> | null,
  state: IKyokuyaSudokuState,
): void => {
  const {
    SUDOKU_SIZE_SQRT,
    difficulty,
    radix,
    score,
    attempt,
    puzzle,
    solution,
    activatedCell,
    hintCell,
    gameTick,
  } = state

  useEffect(() => {
    if (storage == null) return
    storage.dump({
      SUDOKU_SIZE_SQRT,
      difficulty,
      radix,
      score,
      attempt,
      puzzle,
      solution,
      activatedCell,
      hintCell,
      gameTick,
    })
  }, [
    storage,
    SUDOKU_SIZE_SQRT,
    difficulty,
    radix,
    score,
    attempt,
    puzzle,
    solution,
    activatedCell,
    hintCell,
    gameTick,
  ])
}
